select  from pmjk_product

     and id=#{id}
     and producttype=#{producttype}
     and productinfoversion=#{productinfoversion}
     and stakeholderversion=#{stakeholderversion}
     and releaseversion=#{releaseversion}
     and creditenhanceversion=#{creditenhanceversion}
     and otherversion=#{otherversion}
     and createuser=#{createuser}
     and createtimestamp=#{createtimestamp}
     and updatetimestamp=#{updatetimestamp}
     and islock=#{islock}
     and removeflag=#{removeflag}
